// Subscriber registration — defined in the lib slice (not impl) so
// it stays auto-generated. The user touches handle_* in impl.

inline uint32_t ShwaDaemon::subscribe_broadcast_sample(
        BroadcastSampleSubscriber s) {
    std::lock_guard<std::mutex> lk(broadcast_sample_mu_);
    uint32_t id = broadcast_sample_next_id_++;
    broadcast_sample_subs_.push_back({id, std::move(s)});
    return id;
}

inline void ShwaDaemon::unsubscribe_broadcast_sample(uint32_t id) {
    std::lock_guard<std::mutex> lk(broadcast_sample_mu_);
    auto& v = broadcast_sample_subs_;
    v.erase(std::remove_if(v.begin(), v.end(),
              [id](const auto& e) { return e.id == id; }), v.end());
}

inline void ShwaDaemon::broadcast_broadcast_sample(const AccelSample& msg) {
    std::vector<BroadcastSampleEntry> snap;
    {
        std::lock_guard<std::mutex> lk(broadcast_sample_mu_);
        snap = broadcast_sample_subs_;
    }
    for (const auto& e : snap) {
        try { e.fn(msg); }
        catch (...) {
            std::fprintf(stderr,
                "[%s] subscriber %u threw on broadcast.sample — dropping\n",
                kNodeName, e.id);
        }
    }
}

